detailed_optimizations.code_changes:
将循环顺序从i-j-k改为i-k-j，并添加分块：
for (ii = 0; ii < _PB_NI; ii += TI) {
  for (kk = 0; kk < _PB_NK; kk += TK) {
    for (jj = 0; jj < _PB_NJ; jj += TJ) {
      for (i = ii; i < min(ii+TI, _PB_NI); i++) {
        for (k = kk; k < min(kk+TK, _PB_NK); k++) {
          #pragma simd
          for (j = jj; j < min(jj+TJ, _PB_NJ); j++) {
            tmp[i][j] += alpha * A[i][k] * B[k][j];
          }}}}}}}

类似第一个循环的优化，并添加显式预取指令：
for (i = 0; i < _PB_NI; i++) {
  for (k = 0; k < _PB_NJ; k++) {
    __builtin_prefetch(&C[k+4][0], 0, 3);
    #pragma simd
    for (j = 0; j < _PB_NL; j++) {
      D[i][j] += tmp[i][k] * C[k][j];
    }}}

将矩阵B和C转置为列主序存储，使内层循环连续访问：
DATA_TYPE POLYBENCH_2D(B_T,NJ,NK,nj,nk);
DATA_TYPE POLYBENCH_2D(C_T,NL,NJ,nl,nj);
// 在init_array中初始化转置版本
// 在kernel中使用B_T[j][k]和C_T[j][k]

内层循环展开4-8次，使用寄存器变量：
for (k = 0; k < _PB_NK; k+=4) {
  double a0 = A[i][k], a1 = A[i][k+1], a2 = A[i][k+2], a3 = A[i][k+3];
  #pragma simd
  for (j = 0; j < _PB_NJ; j++) {
    tmp[i][j] += alpha * (a0*B[k][j] + a1*B[k+1][j] + a2*B[k+2][j] + a3*B[k+3][j]);
  }}
